THOUGHT: The miscompile is from VectorCombine::shrinkType transforming lshr(zext(<N x i1>), Y) into zext(lshr(<N x i1>, trunc(Y))). Truncating a dynamic shift amount to i1 can introduce poison when the amount is 1. I will modify shrinkType to bail out for LShr when the zext source element type is i1 and the shift amount is not a constant zero vector. This preserves correctness while keeping other shrinkType folds.

```bash
python3 - <<'PY'
import pathlib, re
p = pathlib.Path('llvm/lib/Transforms/Vectorize/VectorCombine.cpp')
s = p.read_text()
# Insert a guard in shrinkType right after we matched the patterns and identified operands.
pattern = r'(bool\s+VectorCombine::shrinkType\s*\([^)]*\)\s*\{\s*[^}]*?if\s*\(!match\(&I, m_c_BitwiseLogic\(m_ZExt\(m_Value\(ZExted\)\),\s*m_Value\(OtherOperand\)\)\)\)\s*&&\s*!match\(&I,\s*m_LShr\(m_ZExt\(m_Value\(ZExted\)\),\s*m_Value\(OtherOperand\)\)\)\)\)\s*return\s+false;\s*[^}]*?Value\s*\*ZExtOperand\s*=\s*I\.getOperand\(I\.getOperand\(0\)\s*==\s*OtherOperand\s*\?\s*1\s*:\s*0\);\s*)'
m = re.search(pattern, s, re.S)
if not m:
    raise SystemExit("Could not locate shrinkType matching block for insertion")
insert_pos = m.end(1)
guard = '''
  // Guard: Do not narrow LShr(zext(<N x i1>), Y) if Y is not an all-zeros constant.
  // Truncating a dynamic shift amount to i1 can introduce poison (shift amount 1).
  if (I.getOpcode() == Instruction::LShr) {
    auto *SmallVecTy = dyn_cast<FixedVectorType>(ZExted->getType());
    if (SmallVecTy) {
      Type *EltTy = SmallVecTy->getElementType();
      if (EltTy->isIntegerTy(1)) {
        if (Constant *C = dyn_cast<Constant>(OtherOperand)) {
          if (!C->isNullValue())
            return false;
        } else {
          return false;
        }
      }
    }
  }
'''
s = s[:insert_pos] + guard + s[insert_pos:]
p.write_text(s)
print("Applied guard in shrinkType to prevent narrowing LShr(zext(i1), Y) unless Y is zero.")
PY
&& submit-patch
```

